class Solution:
    def findLUSlength(self, a: str, b: str) -> int:
        return -1 if a == b else max(len(a), len(b))

solutions.cpp:
class Solution {
public:
    int findLUSlength(string a, string b) {
        if (a == b) return -1;
        return max((int)a.size(), (int)b.size());
    }
};
